   358	        int shiftBy = 0;
   359	        while (true) {
   360	            int next = read();
   361	            //System.out.println("Read additional byte " + Integer.toBinaryString(next));
   362	            value += (next & 0b01111111) << shiftBy; // add all valid bits to the number and continue next cycle
   363	            shiftBy += 7; // the next iteration must be shifted by 7 additional bits
